import mongoose from 'mongoose';
import dotenv from 'dotenv';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
dotenv.config({ path: path.resolve(__dirname, '../.env.local') });
dotenv.config({ path: path.resolve(__dirname, '../.env') });

const MONGO_URI = process.env.MONGO_URI;
if (!MONGO_URI) { console.error('MONGO_URI not found'); process.exit(1); }

const examCategorySchema = new mongoose.Schema({
  name: { type: String, required: true, trim: true },
  type: { type: String, enum: ['Central', 'State'], required: true },
  description: { type: String, trim: true }
}, { timestamps: true });

const examSchema = new mongoose.Schema({
  category: { type: mongoose.Schema.Types.ObjectId, ref: 'ExamCategory', required: true },
  name: { type: String, required: true, trim: true },
  code: { type: String, required: true, uppercase: true, trim: true },
  description: { type: String, trim: true },
  isActive: { type: Boolean, default: true },
  logo: { type: String }
}, { timestamps: true });

const examPatternSchema = new mongoose.Schema({
  exam: { type: mongoose.Schema.Types.ObjectId, ref: 'Exam', required: true },
  title: { type: String, required: true, trim: true },
  duration: { type: Number, required: true, min: 1 },
  totalMarks: { type: Number, required: true, min: 0 },
  negativeMarking: { type: Number, default: 0, min: 0 },
  sections: [{
    name: { type: String, required: true, trim: true },
    totalQuestions: { type: Number, required: true, min: 1 },
    marksPerQuestion: { type: Number, required: true, min: 0 },
    negativePerQuestion: { type: Number, default: 0, min: 0 },
    sectionDuration: { type: Number, min: 0 }
  }]
}, { timestamps: true });

const practiceTestSchema = new mongoose.Schema({
  examPattern: { type: mongoose.Schema.Types.ObjectId, ref: 'ExamPattern', required: true },
  title: { type: String, required: true, trim: true },
  slug: { type: String, lowercase: true, trim: true },
  totalMarks: { type: Number, required: true, min: 0 },
  duration: { type: Number, required: true, min: 1 },
  accessLevel: { type: String, enum: ['FREE', 'PRO'], default: 'FREE' },
  isPYQ: { type: Boolean, default: false },
  pyqYear: { type: Number, default: null },
  pyqShift: { type: String, default: null, trim: true },
  pyqExamName: { type: String, default: null, trim: true },
  publishedAt: { type: Date, default: Date.now },
  questions: [{
    questionText: { type: String, required: true },
    questionImage: { type: String, default: '' },
    options: [{ type: String, required: true }],
    optionImages: [{ type: String, default: '' }],
    correctAnswerIndex: { type: Number, required: true, min: 0 },
    explanation: { type: String, trim: true },
    section: { type: String, required: true, trim: true },
    tags: [{ type: String, trim: true }],
    difficulty: { type: String, enum: ['easy', 'medium', 'hard', 'mixed'], default: 'medium' }
  }]
}, { timestamps: true });

const ExamCategory = mongoose.models.ExamCategory || mongoose.model('ExamCategory', examCategorySchema);
const Exam = mongoose.models.Exam || mongoose.model('Exam', examSchema);
const ExamPattern = mongoose.models.ExamPattern || mongoose.model('ExamPattern', examPatternSchema);
const PracticeTest = mongoose.models.PracticeTest || mongoose.model('PracticeTest', practiceTestSchema);

const REA = 'General Intelligence';
const ENG = 'English Language';
const QA  = 'Quantitative Aptitude';
const GA  = 'General Awareness';

const KEY = [1, 1, 4, 1, 1, 4, 4, 2, 3, 1, 2, 1, 2, 3, 4, 2, 3, 4, 1, 4, 3, 1, 4, 1, 3, 3, 1, 1, 1, 3, 1, 3, 2, 2, 2, 1, 1, 3, 1, 1, 2, 2, 1, 3, 1, 3, 1, 3, 2, 3, 4, 2, 3, 1, 2, 3, 1, 1, 2, 3, 2, 1, 2, 1, 2, 2, 3, 1, 3, 2, 2, 4, 3, 2, 1, 2, 3, 1, 2, 2, 1, 2, 1, 3, 2, 2, 1, 2, 4, 2, 4, 1, 2, 1, 2, 3, 1, 4, 3, 2];
if (KEY.length !== 100) { console.error(`KEY length ${KEY.length}`); process.exit(1); }

const RAW = [
  { s: `General Intelligence`, q: `Statement: "All efficient workers are punctual." Conclusions: I. Some punctual persons are efficient workers. II. All punctual persons are efficient workers.`, o: [`Only I follows`, `Only II follows`, `Both follow`, `Neither follows`], e: `From "All efficient workers are punctual," we can validly infer that some punctual persons are efficient workers (assuming efficient workers exist). The converse (II) is not valid. Option A.` },
  { s: `General Intelligence`, q: `Instruction: Deteromnin2e9 wAuhgich of the following judgments can be made. Judgments: Apple may be swe2e0t.25 S1) Apple is definitely sour. Statement: Some fruits are sweet. Apple is a fruit.`, o: [`Only 1`, `Only 2`, `Both 1 and 2`, `Neither 1 nor 2`], e: `on 29 Aug 2025 S1) Sol: Statement: Some fruits are sweet. Apple is a fruit. Judgments: 1. Apple may be sweet. 2. Apple is definitely sour. Analysis: From "some fruits are sweet" and "apple is a fruit," it is possible that apple is among the sweet fruits. So Judgment 1 can be made. There is no information about apples being sour. Hence, Judgment 2 cannot be made. So, Only 1. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `If MOBILE is coded as 56 and LAPTOP as 80, then what is the code for TABLET?`, o: [`62`, `65`, `66`, `60`], e: `Given: If MOBILE is coded as 56 and LAPTOP as 80. Logic: Sum of place value of letter = Number For, MOBILE - 56 13 + 15 + 2 + 9 + 12 + 5 = 56 For, LAPTOP - 80 12 + 1 + 16 + 20 + 15 + 16 = 80 Similarly, TABLET - ? 20 + 1 + 2 + 12 + 5 + 20 = 60 So, TABLET is coded as 60. Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `In the following question, select the related number from the given alternatives. 4 : 20 :: 6 : ?`, o: [`30`, `36`, `41`, `48`], e: `Given: 4 : 20 :: 6 : ? Logic: 1st number × 5 = 2nd number For, 4 : 20 4 × 5 = 20 Similarly, 6:? 6 × 5 = 30 Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `The sum of ages of a father and son is 56 years. After 4 years, the father will be four times as old as the son. What is the son's present age?`, o: [`8 years`, `10 years`, `12 years`, `14 years`], e: `Given: The sum of ages of a father and son is 56 years. After 4 years, the father will be four times as old as the son. Solution: Sum of present ages of father and son = 56 years After 4 years, father's age = 4 × son's age Let the son's present age = x years Then father's present age = 56 - x After 4 years: Son's age = x + 4 Father's age = 60 - x According to the condition: (60 - x = 4(x + 4)) (60 - x = 4x + 16) (60 - 16 = 4x + x) (44 = 5x) (x = 8.8) So, 8 years is the son's present age. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `From the given alternatives, select the word which cannot be formed using the letters of the word REPUTATION. Each letter may be used only as many times as it appears.`, o: [`RATION`, `PUTTER`, `TONE`, `OPENER`], e: `Given: REPUTATION Letters available: R, E, P, U, T, A, T, I, O, N (Note: T appears twice, all others once) We check options: Option (a): RATION R, A, T, I, O, N (all available) Option (b): PUTTER P, U, T, T, E, R (T used twice, allowed) O ption (c): TONE T, O, N, E (all available) Option (d): OPENER O, P, E, N, E, R (E needed twice, but only one E is available) So, OPENER word which cannot be formed using the letters of the word. Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `Pick the different one.`, o: [`Odissi`, `Manipuri`, `Mohiniyattam`, `Chhau`], e: `Odissi, Manipuri and Mohiniyattam are classical Indian dance forms. Chhau is a semi-classical / folk dance, not a classical one. So, Chhau is odd one out. Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `Which of the following alternative will come at the place of question mark? 12, 24, 48, 96, ?`, o: [`184`, `192`, `198`, `196`], e: `Given: 12, 24, 48, 96, ? Logic: Numbers are multiply by 2. 12 × 2 = 24 24 × 2 = 48 48 × 2 = 96 96 × 2 = 192 So, the missing term 192. Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `If A = add 4, B = triple then subtract 1, C = square then subtract 3, find: 3 A B C`, o: [`100`, `121`, `144`, `169`], e: `Given: A = add 4 B = triple, then subtract 1 C = square Find: 3 A B C 3BAC B: 3 × 3 - 1 = 8 A: 8 + 4 = 12) C: 122= 144 Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `The combined age of two sisters is 30 years. The product of their ages is 209. What are their ages?`, o: [`11 and 19 years`, `12 and 18 years`, `13 and 17 years`, `14 and 16 years`], e: `Given: The combined age of two sisters is 30 years. The product of their ages is 209. Now, we check the options: Option (a): 11 and 19 Product = (11 × 19 = 209) O ption (b): 12 and 18 Product = 216 O ption (c): 13 and 17 Product = 221 O ption (d): 14 and 16 Product = 224 Only option A satisfies both conditions. So, 11 and 19 years are their ages. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `In the following question, select the related word from the given alternatives. Sandstone : Rajasthan :: Limestone : ?`, o: [`Punjab`, `Meghalaya`, `Kerala`, `Ladakh`], e: `Given: Sandstone : Rajasthan :: Limestone : ? Sandstone is abundantly found in Rajasthan. Similarly, Limestone : ? Limestone is abundantly found in Meghalaya. Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `Choose the correct equation using: + = -, - = ×, × = ÷, ÷ = +`, o: [`36 + 6 - 3 × 2 = 27`, `48 - 4 + 6 ÷ 2 = 24`, `60 ÷ 5 - 4 + 2 = 18`, `72 + 8 ÷ 4 - 3 = 20`], e: `Given: Given Sign+ - ×÷ New Sign - ×÷+ Using BODMAS rule. Operation preference wise Symbol Brackets [], , () Orders, of (power), (root), of Division ÷ Multiplication × Addition + - Subtraction Now, we check each options. Option (a): 36 + 6 - 3 × 2 = 27 New equation: 36 - 6 × 3 ÷ 2 = 27 36 - 18 ÷ 2 = 27 36 - 9 = 27 27 = 27 Option (b): 48 - 4 + 6 ÷ 2 = 24 New equation: 48 × 4 - 6 + 2 = 24 192 - 6 + 2 = 24 194 - 6 = 24 188 = 24 Option (c): 60 ÷ 5 - 4 + 2 = 18 New equation: 60 + 5 × 4 - 2 = 18 60 + 20 - 2 = 18 80 - 2 = 18 78 = 18 Option (d): 72 + 8 ÷ 4 - 3 = 20 New equation: 72 - 8 + 4 × 3 = 20 72 - 8 + 12 = 20 84 - 8 = 20 76 = 20 So, 36 + 6 - 3 × 2 = 27 is correct. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `If @ = -, $ = ÷, % = +, # = ×, then 18 % 6 @ 4 # 12 $ 3 = ?`, o: [`6`, `8`, `10`, `12`], e: `Given: 18 % 6 @ 4 # 12 $ 3 = ? Given Symbol@$%# New Sign - ÷+× Using BODMAS rule. Symbol Operation preference wise Brackets [], , () Orders, of (power), (root), of Division ÷ Multiplication × Addition + Subtraction - New equation: 18 + 6 - 4 × 12 ÷ 3 = ? 18 + 6 - 4 × 4 = ? 18 + 6 - 16 = ? 24 - 16 = ? ?=8 Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `In the following question, select the related number from the given alternatives. 45 : 15 :: 81 : ?`, o: [`9`, `18`, `27`, `36`], e: `Given: 45 : 15 :: 81 : ? Logic: 1st number ÷ 3 = 2nd number For, 45 : 15 45 ÷ 3 = 15 Similarly, 81 : ? 81 ÷ 3 = 27 Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `Read the given statements and conclusions carefully. Statements: 1. All flowers are beautiful. 2. Some beautiful things are fragrant. Conclusions: I. Some flowers are fragrant. II. All fragrant things are beautiful.`, o: [`Only I follows`, `Only II follows`, `Both I and II follow`, `Neither I nor II follow`], e: `Statements: 1. All flowers are beautiful. 2. Some beautiful things are fragrant. From the given statements possible Venn diagram will be. Conclusions: I. Some flowers are fragrant. (False, there is no relation between flowers and fragrant). II. All fragrant things are beautiful. (False, some beautiful things are fragrant, so that means all fragrant things are not beautiful). So, Neither I nor II follow. Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `In the following question, select the relationship from the given alternatives. Library : Books :: Orchard : ?`, o: [`Fruits`, `Trees`, `Flowers`, `Seeds`], e: `Given: Library : Books :: Orchard : ? A library is a place where books are kept. Similarly, Orchard : ? An orchard is a place where trees (especially fruit trees) are grown. Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `A family consists of a grandmother, her husband, their three sons, each son's wife, and one son per son. Find total male and female members.`, o: [`5 males, 6 females`, `6 males, 5 females`, `7 males, 4 females`, `6 males, 7 females`], e: `Given: A family consists of a grandmother, her husband, their three sons, each son's wife, and one son per son. From the given information blood relation diagram will be. So, total male and female members are 7 males, 4 females. Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `Center AB (45), Room 12: Roll numbers follow format 4512XX. Question: Which of the following does not belong to this room based on roll number pattern?`, o: [`451201`, `451215`, `451234`, `452112`], e: `Given: Center AB (45), Room 12: Roll numbers follow format 4512XX. That means: First two digits = 45 Next two digits = 12 Last two digits = any number (XX) Now, we check options: Option (a): 451201 45 | 12 | 01 O ption (b): 451215 45 | 12 | 15 O ption (c): 451234 45 | 12 | 34 O ption (d): 452112 45 | 21 | 12 (room number is not 12) So, 452112 does not belong to this room based on roll number pattern. Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `In the following question, select the related letter from the given alternatives. PQRS : SRQP :: LMNO : ?`, o: [`ONML`, `MNOL`, `OLNM`, `NOLM`], e: `Given: PQRS : SRQP :: LMNO : ? Logic: Letters are reversed. For, PQRS : SRQP PQRS SRQP (letters are reversed) Similarly, LMNO : ? LMNO ONML (letters are reversed) Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `If \`+' means \`÷', \`-' means \`×', \`×' means \`+', and \`÷' means \`-', then what is the value of: 24 - 6 + 8 × 4 ÷ 2 ?`, o: [`28`, `26`, `24`, `20`], e: `Given: 24 - 6 + 8 × 4 ÷ 2 ? Given Sign+ - ×÷ New Sign ÷×+ - Using BODMAS rule. Symbol [], , () Operation preference wise Brackets (power), (root), of Orders, of Division ÷ Multiplication × Addition + Subtraction - New equation: 24 × 6 ÷ 8 + 4 - 2 = ? 144 ÷ 8 + 4 - 2 = ? 18 + 4 - 2 = ? 22 - 2 = ? ? = 20 Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `In MP (07), seat numbers must not repeat in the same room. Which set is valid?`, o: [`701021, 701021, 701034, 701034`, `701045, 701056, 701045, 701067`, `701111, 701112, 701113, 701114`, `701021, 701031, 701021, 701041`], e: `Given: In MP (07), seat numbers must not repeat in the same room. Now, we check each options: Option (a): 701021, 701021, 701034, 701034 (repetition) Option (b): 701045, 701056, 701045, 701067 (repetition) Option (c): 701111, 701112, 701113, 701114 (all seat numbers are different) Option (d): 701021, 701031, 701021, 701041 (repetition) So, 701111, 701112, 701113, 701114 set is valid. Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `In the following question, select the related letter from the given alternatives. ACE : BDF :: KMO : ?`, o: [`LNP`, `LNO`, `MNP`, `LMP`], e: `Given: ACE : BDF :: KMO : ? Logic: Letters are increasing + 1 place. For, ACE : BDF A + 1 = B, C + 1 = D, E + 1 = F Similarly, KMO : ? K + 1 = L, M + 1 = N, O + 1 = P So, KMO : LNP Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `Find the missing term: BFL, CHM, DJN, ?`, o: [`EJO`, `EIP`, `EKN`, `ELO`], e: `Given: BFL, CHM, DJN, ? Logic: 1st letter + 1, 2nd letter + 2 and 3rd letter + 1 place. For, 1st letter B + 1 = C, C + 1 = D, D + 1 = E For, 2nd letter F + 2 = H, H + 2 = J, J + 2 = L For, 3rd letter L + 1 = M, M + 1 = N, N + 1 = O So, the missing term is ELO. Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `A train 240 m long passes a pole in 15 s. Its speed is?`, o: [`58 km/h`, `54 km/h`, `60 km/h`, `72 km/h`], e: `Given: A train 240 m long passes a pole in 15 s. Speed = Distance ÷ Time = 240 ÷ 15 = 16 m/s Convert m/s to km/h: 18 16 × = 57.6 km/h 5 So, 58 km/h is speed. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `Which of the following alternative will come at the place of question mark? 12 : 144 :: 15 : ?`, o: [`200`, `210`, `225`, `240`], e: `Given: 12 : 144 :: 15 : ? Logic: 1st number2= 2nd number For, 12 : 144 122= 144 Similarly, 15 : ? 152= 225 Thus, correct option is (c).` },
  { s: `General Awareness`, q: `What is the main objective of the Global Hunger Index (GHI)?`, o: [`To measure global GDP growth rates`, `To rank countries based on military strength`, `To assess and track hunger levels at global, regional, and national levels`, `To evaluate literacy rates worldwide`], e: `N/A` },
  { s: `General Awareness`, q: `Assertion (A): A country may achieve high GDP growth yet continue to face widespread unemployment. Reason (R): GDP growth measures total economic output but does not necessarily ensure equitable job creation.`, o: [`Both A and R are true, and R is the correct explanation of A`, `Both A and R are true, but R is not the correct explanation of A`, `A is true, but R is false`, `A is false, but R is true`], e: `The correct answer is (A) Both A and R are true, and R is the correct explanation of A Explanation: · GDP measures the market value of goods and services. Growth can occur through automation or capital-intensive sectors without hiring more people (Jobless growth). · Therefore, R explains why A is possible. Information Booster: · Jobless growth is a phenomenon where the economy grows but unemployment remains high or even increases. Additional Knowledge: · Inclusive growth is the term used for growth that creates employment and reduces poverty.` },
  { s: `General Awareness`, q: `Match the Indian freedom fighters with their associated movements: A) Bal Gangadhar Tilak -- 3) Home Rule Movement B) Mahatma Gandhi -- 1) Quit India Movement C) Subhas Chandra Bose -- 2) Indian National Army D) Bhagat Singh -- 4) Hindustan Socialist Republican Association`, o: [`A-3, B-1, C-2, D-4`, `A-1, B-3, C-4, D-2`, `A-2, B-4, C-1, D-3`, `A-4, B-2, C-3, D-1`], e: `The correct answer is (A) A-3, B-1, C-2, D-4 Explanation: · Bal Gangadhar Tilak launched the Home Rule League in 1916. · Mahatma Gandhi led the Quit India Movement in 1942. · Subhas Chandra Bose took command of the Indian NatioCnoaplyArirgmhyt ©(Az2a0d26HiAndddFaa2u4j)7in 1943. · Bhagat Singh was a key leader of the HSRA. Information Booster: · Tilak is known as 'Lokmanya' and famously said, "Swaraj is my birthright and I shall have it." Additional Knowledge: · The Quit India Movement is also known as the 'August Kranti'.` },
  { s: `General Awareness`, q: `Read the below statements marked as Assertion (A) and Reason (R). Mark the correct option: Assertion (A): Gupta period temples show the beginning of structural temple architecture in India. Reason (R): The use of dressed stone and brick during the Gupta period led to permanent temple structures.`, o: [`Both A and R are true, and R is the correct explanation of A`, `Both A and R are true, but R is not the correct explanation of A`, `A is true, but R is false`, `Both A and R are false`], e: `The correct answer is (A) Both A and R are true, and R is the correct explanation of A Explanation: · The Gupta period is considered the 'Golden Age' of Indian architecture where free-standing structural temples emerged. · Before this, rock-cut architecture was more prevalent; the shift to dressed stone and brick allowed for permanent, complex structures. Information Booster: · The Dashavatara Temple at Deogarh is a classic example of Gupta structural temple architecture. Additional Knowledge: · Gupta temples often featured a flat roof initially, evolving into a shikhara (tower).` },
  { s: `General Awareness`, q: `Consider the following statements: Statement 1: Akbar introduced the Mansabdari system to organize the Mughal administrative and military structure. Statement 2: The Mansabdari system classified officials based on rank and the number of cavalry they maintained. Which of the statements is/are correct?`, o: [`Only 1`, `Only 2`, `Both 1 and 2`, `Neither 1 nor 2`], e: `The correct answer is (C) Both 1 and 2 Explanation: · Akbar introduced the Mansabdari system to create a centralized administrative structure. · The system used 'Zat' to indicate personal rank and status, and 'Sawar' to indicate the number of cavalrymen (cavalry) the official was required to maintain. Information Booster: · Mansabdars received their salaries either in cash (Naqdi) or through land assignments (Jagirs). Additional Knowledge: · The system was not hereditary and depended on the will of the Emperor.` },
  { s: `General Awareness`, q: `Consider the following statements about Olympic Games rules: 1. The Olympic Games are held every four years. 2. Only professional athletes are allowed to participate in all Olympic sports. Which of the above statements is/are Correct?`, o: [`Only 1 is Correct`, `Only 2 is Correct`, `1 and 2 both are Correct`, `Neither 1 nor 2 are Correct`], e: `The correct answer is (A) Only 1 is Correct Explanation: · The Olympic Games are a quadrennial event, occurring every four years. · Statement 2 is incorrect because while many Olympians are professionals, the Olympics historically emphasized amateurism, and today both professionals and amateurs can compete depending on the sport's federation rules. Information Booster: · The International Olympic Committee (IOC) was founded in 1894 by Pierre de Coubertin. Additional Knowledge: · The first modern Olympics were held in Athens, Greece, in 1896.` },
  { s: `General Awareness`, q: `Which sport did Neeraj Chopra win a gold medal in at the Tokyo 2020 Olympics?`, o: [`Wrestling`, `Boxing`, `Javelin Throw`, `Badminton`], e: `The correct answer is (C) Javelin Throw Explanation: · Neeraj Chopra won the gold medal in the Javelin Throw event with a throw of 87.58m at the Tokyo 2020 Olympics. · He became the first Indian track and field athlete to win an Olympic gold medal. Information Booster: · Neeraj Chopra is only the second Indian to win an individual Olympic gold after Abhinav Bindra. Additional Knowledge: · Wrestling (Option A): Ravi Kumar Dahiya won Silver in Tokyo. · Boxing (Option B): Lovlina Borgohain won Bronze in Tokyo. · Badminton (Option D): P.V. Sindhu won Bronze in Tokyo.` },
  { s: `General Awareness`, q: `Which Indian government body regulates civil aviation in India?`, o: [`Airports Authority of India (AAI)`, `Directorate General of Civil Aviation (DGCA)`, `Ministry of Defence`, `Bureau of Civil Aviation Security`], e: `The correct answer is (B) Directorate General of Civil Aviation (DGCA) Explanation: · The DGCA is the statutory body of the Government of India to regulate civil aviation in India. · It primarily deals with safety issues and is responsible for regulation of air transport services to/from/within India and for enforcement of civil air regulations. Information Booster: · DGCA is headquartered in New Delhi and functions under the Ministry of Civil Aviation. Additional Knowledge: · AAI (Option A): Manages the infrastructure of airports. · BCAS (Option D): Responsible for laying down standards for civil aviation security.` },
  { s: `General Awareness`, q: `What is the primary objective of the Aditya-L1 mission lCaoupnycrhigedhtb©y I2S0R2O6?Adda247`, o: [`To explore the surface of Mars`, `To study the Sun's corona and solar activities`, `To deploy communication satellites in orbit`, `To conduct experiments on the Moon's surface`], e: `The correct answer is (B) To study the Sun's corona and solar activities Explanation: · Aditya-L1 is India's first solar mission to study the Sun. · It is placed in a halo orbit around the Lagrange point 1 (L1) of the Sun-Earth system, about 1.5 million km from Earth. Information Booster: · The mission studies solar winds, Coronal Mass Ejections (CMEs), and the heating of the solar corona. Additional Knowledge: · Mars Exploration (Option A): Mangalyaan was ISRO's mission for Mars. · Moon Surface (Option D): Chandrayaan series focuses on the Moon.` },
  { s: `General Awareness`, q: `The Iron Pillar of Delhi is primarily composed of which metal?`, o: [`Copper`, `Iron`, `Bronze`, `Aluminium`], e: `The correct answer is (B) Iron Explanation: · The Iron Pillar of Delhi is famous for its high resistance to corrosion, showcasing the advanced metallurgy of ancient India. · It is made of 98% wrought iron and was erected during the Gupta Dynasty, likely during the reign of Chandragupta II. Information Booster: · The pillar's rust-resistance is attributed to a passive protective film of crystalline iron hydrogen phosphate hydrate forming on the surface. Additional Knowledge: · Copper (Option A): Used in the Indus Valley Civilization for tools. · Bronze (Option C): An alloy of copper and tin, prominent in the Harappan culture. · Aluminium (Option D): A modern metal not extracted in ancient India.` },
  { s: `General Awareness`, q: `Assertion (A): India successfully soft-landed on the Moon's south polar region through Chandrayaan-3 in 2023. Reason (R): The mission demonstrated India's capability in advanced space exploration and lunar surface operations.`, o: [`Both A and R are true, and R is the correct explanation of A`, `Both A and R are true, but R is not the correct explanation of A`, `A is false, but R is true`, `A is true, but R is false`], e: `The correct answer is (A) Both A and R are true, and R is the correct explanation of A Explanation: · Chandrayaan-3 landed on August 23, 2023, making India the first country to land near the lunar South Pole. · The success proves the technological maturity of ISRO in executing complex soft-landing maneuvers. Information Booster: · The landing site of Chandrayaan-3 has been named 'Shiv Shakti Point'. Additional Knowledge: · India is the fourth country to achieve a soft landing on the Moon after the USA, Russia, and China.` },
  { s: `General Awareness`, q: `Read the below statements marked as Assertion (A) and Reason (R). Mark the correct options: Assertion (A): The Goods and Services Tax (GST) was introduced in India in 2017 to unify the indirect tax structure. Reason (R): GST subsumed various central and state taxes into a single tax system.`, o: [`Both A and R are true, and R is the correct explanation of A`, `Both A and R are true, but R is not the correct explanation of A`, `A is false, but R is true`, `A is true, but R is false`], e: `The correct answer is (A) Both A and R are true, and R is the correct explanation of A Explanation: · GST was implemented on July 1, 2017, to create a 'One Nation, One Tax' system. · It unified the market by replacing multiple indirect taxes like Excise Duty, VAT, and Service Tax, thus explaining why it was introduced. Information Booster: · GST is a destination-based tax on consumption of goods and services. Additional Knowledge: · The GST Council, chaired by the Union Finance Minister, is the governing body for GST.` },
  { s: `General Awareness`, q: `Read the following two statements carefully and choose the correct option: Statement 1: The Green Revolution in India significantly increased food grain production. Statement 2: High-yielding variety (HYV) seeds and improved irrigation were major components of the Green Revolution.`, o: [`Only 1`, `Only 2`, `Both 1 and 2 are correct`, `Neither 1 nor 2 is correct`], e: `The correct answer is (C) Both 1 and 2 are correct Explanation: · The Green Revolution (starting in the mid-1960s) transformed India from a food-deficient nation to a self-sufficient one. · This was achieved through the 'Package Technology' comprising HYV seeds (especially wheat and rice), chemical fertilizers, and assured irrigation. Information Booster: · M.S. Swaminathan is known as the Father of the Green Revolution in India. Additional Knowledge: · Norman Borlaug is known as the Father of the Green Revolution globally.` },
  { s: `General Awareness`, q: `Assertion (A): According to Census 2011, Kerala has the highest literacy rate among Indian states. Reason (R): Kerala has historically invested heavily in education and social development.`, o: [`Both A and R are true, and R is the correct explanation of A`, `Both A and R are true, but R is not the correct explanation of A`, `A is false, but R is true`, `A is true, but R is false`], e: `The correct answer is (A) Both A and R are true, and R is the correct explanation of A Explanation: · In Census 2011, Kerala recorded a literacy rate of 94.00%, the highest in India. · This achievement is a direct result of long-term state policies focusing on primary education and public health. Information Booster: · Bihar had the lowest literacy rate in the 2011 Census at 61.80%. Additional Knowledge: · Literacy in Census is defined as the ability to read and write with understanding in any language for a person aged 7 and above.` },
  { s: `General Awareness`, q: `Assertion (A): India's National Green Hydrogen Mission aims to position the country as a global hub for green hydrogen production. Reason (R): Green hydrogen is produced using renewable energy sources and helps reduce carbon emissions.`, o: [`Both A and R are true, and R is the correct explanation of A`, `Both A and R are true, but R is not the correct explanation of A`, `A is true, but R is false`, `A is false, but R is true`], e: `The correct answer is (A) Both A and R are true, and R is the correct explanation of A Explanation: · The mission was approved to decarbonize the economy and reduce dependence on fossil fuel imports. · Since 'Green' hydrogen is made via electrolysis powered by renewables, it aligns with India's climate goals, justifying the push to become a global hub. Information Booster: · The mission targets a production capacity of at least 5 MMT of green hydrogen per year by 2030. Additional Knowledge: · Green hydrogen differs from 'Grey' (from natural gas) and 'Blue' (with carbon capture) hydrogen.` },
  { s: `General Awareness`, q: `Which of the following minerals is most widely used in the production of stainless steel in India?`, o: [`Bauxite`, `Manganese`, `Limestone`, `Gypsum`], e: `The correct answer is (B) Manganese Explanation: · Manganese is an essential raw material for manufacturing steel and ferromanganese alloys. · Nearly 10 kg of manganese is required to manufacture one tonne of steel, as it helps in deoxidizing and desulfurizing. Information Booster: · Odisha is a leading producer of Manganese in India. Additional Knowledge: · Bauxite (Option A): Ore used for Aluminium production. · Limestone (Option C): Used primarily in the Cement industry. · Gypsum (Option D): Used in making fertilizer and Plaster of Paris.` },
  { s: `General Awareness`, q: `Under the Disaster Management Act, 2005, who chairs the National Disaster Management Authority (NDMA)?`, o: [`Home Minister`, `Prime Minister`, `Defence Minister`, `Cabinet Secretary`], e: `The correct answer is (B) Prime Minister Explanation: · The NDMA is the apex statutory body for disaster management in India. · According to the DM Act 2005, the Prime Minister is the ex-officio Chairperson of the NDMA. Information Booster: · State Disaster Management Authorities (SDMAs) are chaired by the respective Chief Ministers. Additional Knowledge: · The Home Minister (Option A): Usually serves as the Vice-Chairperson or head of the executive committee.` },
  { s: `General Awareness`, q: `Read the following statements about human digestive enzymes: 1. Amylase helps in the digestion of starch into simple sugars. 2. Pepsin works in an acidic medium in the stomach. 3. Bile contains enzymes that digest proteins. Which of the above statements are correct?`, o: [`Only 1 and 2 are correct`, `Only 2 and 3 are correct`, `Only 1 and 3 are correct`, `1, 2 and 3 are correct`], e: `The correct answer is (A) Only 1 and 2 are correct Explanation: · Salivary amylase begins the breakdown of starch in the mouth. · Pepsin is a protein-digesting enzyme in the stomach that requires the acidic pH provided by HCl. · Statement 3 is incorrect because Bile does not contain enzymes; it emulsifies fats. Information Booster: · Bile is produced by the liver and stored in the gallbladder. Additional Knowledge: · Trypsin is another protein-digesting enzyme, but it works in the small intestine.` },
  { s: `General Awareness`, q: `Under PM-KISAN scheme, eligible farmers receive financial assistance of:`, o: [`4,000 per year`, `5,000 per year`, `6,000 per year`, `10,000 per year`], e: `The correct answer is (C) 6,000 per year Explanation: · Pradhan Mantri Kisan Samman Nidhi (PM-KISAN) is a central sector scheme. · It provides an income support of 6,000 per year in three equal installments of 2,000 directly into the bank accounts of farmer families. Information Booster: · The scheme was launched in February 2019 (effective from December 2018). Additional Knowledge: · It is implemented by the Ministry of Agriculture and Farmers Welfare.` },
  { s: `General Awareness`, q: `If the atomic number of an element is 11, the number ofCeolpeycrtirgohnts©in2it0s2o6uAtderdma2o4s7t shell is:`, o: [`1`, `2`, `8`, `11`], e: `The correct answer is (A) 1 Explanation: · The atomic number 11 belongs to Sodium (Na). · Electronic configuration: The first shell (K) holds 2, the second (L) holds 8, leaving 1 electron for the third shell (M). Configuration is 2, 8, 1. Information Booster: · Elements with 1 electron in the outermost shell are highly reactive metals (Alkali metals). Additional Knowledge: · Valency of an element with 1 valence electron is +1.` },
  { s: `General Awareness`, q: `Fill in the Blank: The classical dance form \`Kathakali' originated in ________.`, o: [`Tamil Nadu`, `Karnataka`, `Kerala`, `Andhra Pradesh`], e: `The correct answer is (C) Kerala Explanation: · Kathakali is a 'story play' genre of art, distinguished by its colorful make-up and costumes. · It originated in the state of Kerala and is one of the 8 classical dances of India recognized by Sangeet Natak Akademi. Information Booster: · Mohiniyattam is the other classical dance form from Kerala. Additional Knowledge: · Tamil Nadu (Option A): Bharatnatyam. · Andhra Pradesh (Option D): Kuchipudi.` },
  { s: `General Awareness`, q: `Consider the following statements regarding the National Green Hydrogen Mission: 1. It aims to make India a global hub for the production and export of green hydrogen. 2. It was launched in 2023. 3. It focuses only on hydrogen production for domestic fertilizer industries.`, o: [`Only 1 and 2 are correct`, `Only 2 and 3 are correct`, `Only 1 and 3 are correct`, `All 1, 2 and 3 are correct`], e: `The correct answer is (A) Only 1 and 2 are correct Explanation: · The Mission was formally launched in early 2023. · Statement 3 is incorrect because the mission has a broad scope, including export, transport, and industrial sectors, not just fertilizers. Information Booster: · Green Hydrogen is defined as hydrogen produced by splitting water using electricity generated from renewable sources. Additional Knowledge: · The mission helps India meet its 'Panchamrit' climate targets announced at COP26.` },
  { s: `General Awareness`, q: `When was the Goods and Services Tax (GST) implemented in India?`, o: [`2015`, `2016`, `2017`, `2018`], e: `The correct answer is (C) 2017 Explanation: · GST was launched in India on the midnight of July 1, 2017. · It replaced multiple cascading taxes levied by the central and state governments. Information Booster: · The 101st Constitution Amendment Act paved the way for GST implementation. Additional Knowledge: · Assam was the first state to ratify the GST Bill.` },
  { s: `General Awareness`, q: `Large-scale wind energy projects require specific geographical conditions. Which of the following factors is most important for maximizing wind power generation?`, o: [`High humidity and dense forest cover`, `Consistent high-speed winds in open coastal or elevated areas`, `Proximity to mineral-rich regions`, `Abundant groundwater availability`], e: `The correct answer is (B) Consistent high-speed winds in open coastal or elevated areas Explanation: · Wind turbines convert kinetic energy from wind into electricity; hence, wind speed is the most critical factor (power is proportional to the cube of wind speed). · Coastal and elevated areas experience fewer obstructions and higher pressure gradients, providing steady winds. Information Booster: · Tamil Nadu, Gujarat, and Karnataka are the leading states in wind energy capacity in India. Additional Knowledge: · Forest cover (Option A) actually reduces wind speed due to friction.` },
  { s: `General Awareness`, q: `Consider the following statements about Venus: 1. Venus rotates in a retrograde direction. 2. It is often called Earth's twin due to its similar size and mass. Which of the above is/are correct?`, o: [`Statement 1 only`, `Statement 2 only`, `Both 1 and 2`, `Neither 1 nor 2`], e: `The correct answer is (C) Both 1 and 2 Explanation: · Venus is the only planet along with Uranus that rotates from East to West (Retrograde). · It is called 'Earth's Twin' because its size, mass, and density are very similar to Earth. Information Booster: · Venus is the hottest planet in the solar system due to a runaway greenhouse effect caused by its thick CO2 atmosphere. Additional Knowledge: · A day on Venus is longer than its year.` },
  { s: `Quantitative Aptitude`, q: `A decorative object consists of a cylinder and a cone mounted on top of it. The radius of both parts is 7 cm. The height of the cylindrical part is 20 cm, and the slant height of the conical part is 25 cm. Determine the total surface area of the object (base included).`, o: [`1254cm2`, `1386cm2`, `1540cm2`, `1584cm2`], e: `Given: Radius of cylinder and cone (r) = 7 cm Height of cylinder (h) = 20 cm Slant height of cone (l) = 25 cm Formula Used: Total Surface Area (TSA) = CSA of Cylinder + CSA of Cone + Area of Base TSA = 2rh + rl + r2 = r(2h + l + r) Solution: Substitute the given values into the formula: 22 T SA = × 7 × (2(20) + 25 + 7) 7 = 22 × (40 + 25 + 7) = 22 × 72 = 1584 cm2 Final Answer So the correct answer is (d)` },
  { s: `Quantitative Aptitude`, q: `A regular tetrahedron (triangular pyramid) has an edge length of 6 cm. Find its total surface area.`, o: [`24`, `36`, `18`, `12`], e: `Given: Edge length (a) = 6 cm Formula Used: Total Surface Area of Regular Tetrahedron = a2 3 Solution: Substitute the value of a = 6: TSA = 62 3 TSA = 36 3 cm2 Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `In which type of triangle do the Centroid, Incenter, Circumcenter, and Orthocenter all coincide at the same point?`, o: [`Isosceles triangle`, `Right-angled triangle`, `Equilateral triangle`, `Scalene triangle`], e: `Given: Condition: Centroid, Incenter, Circumcenter, and Orthocenter coincide. Formula Used: Properties of triangles. Solution: In an equilateral triangle, all sides and angles are equal. Due to this symmetry, the medians, angle bisectors, perpendicular bisectors, and altitudes are the same lines. Therefore, their points of intersection (Centroid, Incenter, Circumcenter, and Orthocenter) all lie at the exact same point. Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `Two parallel chords of lengths 10 cm and 24 cm are drawn in a circle of radius 13 cm. If the chords are on opposite sides of the center, what is the distance between them?`, o: [`17 cm`, `12 cm`, `7 cm`, `14 cm`], e: `Given: Radius (r) = 13 cm Chord 1 (L1) = 10 cm Chord 2 (L2) = 24 cm Chords are on opposite sides. Formula Used: r2 - (L/2)2 Distance from center d = Total distance = d1 + d 2 Solution: F or Chord 1 (10 cm): Half-length = 5 cm. d 1 = 132 - 52 = 169 - 25 = 144 = 12 cm. For Chord 2 (24 cm): Half-length = 12 cm. d 2 = 132 - 122 = 169 - 144 = 25 = 5 cm. Since they are on opposite sides, add the distances: Distance = 12 + 5 = 17 cm Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `Runner A completes a lap of a circular track in 12 minutes, while Runner B takes 18 minutes. If they start at the same time from the same point, after how many minutes will they meet again at the starting point?`, o: [`24 minutes`, `36 minutes`, `48 minutes`, `72 minutes`], e: `Given: Time taken by A = 12 minutes Time taken by B = 18 minutes Formula Used: Meeting time = LCM(Time A, Time B) Solution: Find the Least Common Multiple (LCM) of 12 and 18. Factors of 12 = 22 × 3 Factors of 18 = 2 × 32 LCM = 22 × 32 = 4 × 9 = 36 They will meet again at the starting point after 36 minutes. Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `If cos θ = −12/13 and θ lies in the third quadrant, find the value of tan θ.`, o: [`−5/12`, `5/13`, `5/12`, `−12/5`], e: `cos θ = −12/13, base=12, hyp=13, perpendicular = √(169−144) = 5. In 3rd quadrant tan is positive: tan θ = 5/12. Option C.` },
  { s: `Quantitative Aptitude`, q: `If tan(2A) = cot(A - 18), where 2A is an acute angle, find the value of A.`, o: [`36`, `45`, `24`, `30`], e: `Given: t an(2A) = cot(A - 18) Formula Used: t an = cot(90 - ) Solution: Convert tan to cot : c ot(90 - 2A) = cot(A - 18) Equate the angles: 90 - 2A = A - 18 90 + 18 = A + 2A 108 = 3A 108 A= 3 A = 36 Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `Arrange the following in descending order: √2, ∛3, ⁶√6`, o: [`∛3 > √2 > ⁶√6`, `√2 > ⁶√6 > ∛3`, `∛3 > ⁶√6 > √2`, `⁶√6 > √2 > ∛3`], e: `Express as 6th roots: √2 = 8^(1/6), ∛3 = 9^(1/6), ⁶√6 = 6^(1/6). Order: 9 > 8 > 6, so ∛3 > √2 > ⁶√6. Option A.` },
  { s: `Quantitative Aptitude`, q: `Simplify: (√5 − √2)²`, o: [`8 − √15`, `7 − 2√10`, `2 − 2√10`, `8 + 2√15`], e: `(√5 − √2)² = 5 + 2 − 2√10 = 7 − 2√10. Option B.` },
  { s: `Quantitative Aptitude`, q: `A sum of 6,450 is borrowed at 5% simple interest per annum, to be paid back in 2 equal annual installments. What is the amount of each installment?`, o: [`3,000`, `3,225`, `3,461`, `3,150`], e: `Given: Principal (Borrowed Sum, P): 6,450 Rate of Interest (R): 5% per annum Time (T): 2 years Installments: 2 equal annual installments Formula Used: Total Amount to be Paid (Debt): P ×R×T A=P+ 100 Installment Formula (to discharge a future Debt A): I= 100 × A 100 × T + R×T ×(T -1) 2 (Where I is the annual installment amount) Solution: First, calculate the total amount (Debt) payable at the end of 2 years on the borrowed sum. 6450 × 5 × 2 A = 6450 + 100 64500 A = 6450 + 100 A = 6450 + 645 = 7, 095 Now, determine the installment $I$ that will settle this debt of 7,095 in 2 years. Using the installment formula: I = 7095 × 100 100 × 2 + 5×2×1 2 709500 I= 200 + 5 709500 I= 205 I 3, 460.97 Rounding to the nearest rupee, the installment is 3,461. Alternate Solution (Short Trick): Let the annual` },
  { s: `Quantitative Aptitude`, q: `An airplane flying at a constant height of 3000 3m is observed at an angle of elevation of 60. After 15 seconds, the angle of elevation becomes 30. What is the speed of the plane?`, o: [`720km/hr`, `1440km/hr`, `800km/hr`, `960km/hr`], e: `Given: Height (h) = 3000 3m Angles: 60to 30. Time = 15 seconds. Formula Used: Distance = h(cot 30 - cot 60) Speed = Distance / Time Solution: U sing h = 3000 3m for calculation: 1 Distance = 3000 3( 3 - ) 3 3-1 = 3000 3( ) 3 2 = 3000 3( ) 3 = 6000 m. 6000 Speed = = 400 m/s. 15 Convert to km/hr: 18 4 00 × = 80 × 18 = 1440 km/hr. 5 Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `Pipes P and Q can fill a tank in 12 hours and 15 hours respectively. Pipe R can empty it in 20 hours. If all three pipes are opened together, how long will it take to fill the tank?`, o: [`10 hours`, `12 hours`, `15 hours`, `18 hours`], e: `Given: P fills in 12 hrs, Q in 15 hrs, R empties in 20 hrs. Formula Used: 111 Net Rate = + - P QR Solution: 111 Work per hour = + - 12 15 20 LCM of 12, 15, 20 is 60. 5+4-3 6 1 Rate = = = . 60 60 10 Time taken = 10 hours. Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `A shopkeeper marks his goods 40% above the cost price and allows a discount of 25%. What is his gain or loss percent?`, o: [`5% Loss`, `5% Gain`, `10% Gain`, `No Profit No Loss`], e: `Given: Markup = 40% Discount = 25% Formula Used: xy Successive percentage: x - y - 100 Solution: Let CP = 100. Marked Price = 140. 1 Discount = 25% of 140 = × 140= 35. 4 Selling Price = 140 - 35 = 105. Gain = 105 - 100 = 5. Gain % = 5%. Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `Two cyclists start from a junction. One travels North at 15 km/h and the other travels West at 20 km/h. How far apart are they after 2 hours?`, o: [`50 km`, `70 km`, `35 km`, `45 km`], e: `Given: Speed 1 (North) = 15 km/h. Speed 2 (West) = 20 km/h. Time = 2 hours. Formula Used: Distance = d2 + d2 (Pythagoras Theorem) 1 2 Solution: Distance North = 15 × 2 = 30 km. Distance West = 20 × 2 = 40 km. Separation = 302 + 402 = 900 + 1600 = 2500 = 50 km Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `A square lawn has a side of 50 meters. A path of 2.5 meters width is constructed inside along its boundary. Find the difference between the outer and inner perimeters.`, o: [`10 meters`, `20 meters`, `15 meters`, `25 meters`], e: `Given: Side of square = 50 m. Path width = 2.5 m (inside). Formula Used: Perimeter = 4 × side. Solution: Outer side = 50 m. Outer Perimeter = 4 × 50 = 200 m. Inner side = 50 - 2(2.5) = 50 - 5 = 45 m. Inner Perimeter = 4 × 45 = 180 m. Difference = 200 - 180 = 20 meters. Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `The sides of a triangle are in the ratio 5:12:13. If the perimeter is 60 cm, find the length of the longest side.`, o: [`24 cm`, `26 cm`, `20 cm`, `13 cm`], e: `Given: Ratio = 5:12:13. Perimeter = 60 cm. Formula Used: Perimeter = Sum of sides. Solution: Let sides be 5x, 12x, 13x. 5x + 12x + 13x = 60 30x = 60 x = 2. Longest side = 13x = 13 × 2 = 26 cm. Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `Which of the following numbers is a perfect square and is divisible by 9?`, o: [`100`, `196`, `225`, `400`], e: `Given: Options: 100, 196, 225, 400. Formula Used: Divisibility by 9: Sum of digits must be divisible by 9. Solution: A: 100 (Sum 1) - No. B: 196 (Sum 16) - No. C: 225 (Sum 9) - Yes. Also 152= 225. D: 400 (Sum 4) - No. Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `By selling an article for 810, a man loses 10%. What is the cost price?`, o: [`900`, `891`, `729`, `1000`], e: `Given: SP = 810. Loss = 10%. Formula Used: SP = CP × 100 - Loss% 100 Solution: 810 = CP × 90 810 × 110000 CP = 90 CP =9 × 100 = 900. Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `The average of 5 numbers is 20. If one number, which is 20, is removed, what is the average of the remaining 4 numbers?`, o: [`19`, `21`, `20`, `25`], e: `Given: Average of 5 numbers = 20. Removed number = 20. Formula Used: Average = Sum / Count. Solution: Sum = 20 × 5 = 100. New Sum = 100 - 20 = 80. New Count = 4. New Average = 80 / 4 = 20. Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `A person sold an article at a loss of 10%. Had he sold it for 150 more, he would have gained 20%. What is the cost price?`, o: [`400`, `500`, `600`, `450`], e: `Given: Difference between +20% (gain) and -10% (loss) is 150. Formula Used: Percentage Difference = Value Difference. Solution: Total gap = 20 - (-10) = 30%. 30% of CP = 150. 150 CP = × 100 30 CP = 5 × 100 = 500. Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `A candidate scored 360 marks out of 600. What is the percentage of marks obtained?`, o: [`55%`, `60%`, `65%`, `70%`], e: `Given: Marks Scored = 360. Total Marks = 600. Formula Used: Percentage = Scored × 100 Total Solution: 360 × 100 600 = 36 × 10 6 = 6 × 10 = 60% Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `Which of the following is an irrational number?`, o: [`√16`, `3.14`, `22/7`, `π`], e: `√16 = 4 (rational), 3.14 (rational), 22/7 (rational), π (non-terminating non-recurring, irrational). Option D.` },
  { s: `Quantitative Aptitude`, q: `If the binary number 100102is divided by 112, the quotient in decimal system is:`, o: [`4`, `5`, `6`, `8`], e: `Given: Binary numbers: 100102 and 112. Solution: Convert to decimal: 100102 = 1(24) + 0 + 0 + 1(21) + 0 = 16 + 2 = 18. 112 = 1(21) + 1(20) = 2 + 1 = 3. Divide: 18 / 3 = 6. Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `A container is filled with liquid to 80% of its capacity. If 20 liters are removed, it becomes 60% full. What is the total capacity?`, o: [`80 liters`, `100 liters`, `120 liters`, `150 liters`], e: `Given: Change from 80% to 60% by removing 20 liters. Solution: Difference in percentage = 80% - 60% = 20%. 20% of Capacity = 20 Liters. 1% = 1 Liter. 100% = 100 Liters. Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `Find the equation of the line passing through the points (2, 3) and (4, 7).`, o: [`y = 2x - 1`, `y = 2x + 1`, `y = x + 1`, `y = 3x - 3`], e: `Given: Points (2, 3) and (4, 7). Formula Used: Slope m = y2 - y1 x - x 2 1 Equation: y - y1 = m(x - x1 ) Solution: 7-3 4 Slope m = = = 2. 4-2 2 Using point (2, 3): y - 3 = 2(x - 2) y - 3 = 2x - 4 y = 2x - 1. Final Answer So the correct answer is (a)` },
  { s: `English Language`, q: `Choose the correct active form of the given sentence: Admission was denied to her parents by the institution.`, o: [`Her parents was denied admission by the institution.`, `The institution denied admission to her parents.`, `her parents will be denied admission by the institution.`, `The institution has been denying admission to her parents.`], e: `The correct option is (B). Explanation (Passive to Active): Given sentence is in passive voice: "Admission was denied to her parents by the institution." Identify the parts: Object (receiver of action): admission Verb (passive): was denied Agent (doer): the institution Indirect object: to her parents Rule: In passive to active conversion, the agent (introduced by by) becomes the subject, and the object becomes the object. The verb changes from was + V3 to V2 (simple past) because the passive is in simple past. Active structure: Subject + V2 + Object + (to/for + indirect object) Thus: The institution denied admission to her parents. Why other options are incorrect: (A) "Her parents was denied admission..." is grammatically wrong because parents is plural, so it should be were, and it also k` },
  { s: `English Language`, q: `Fill in the blank with the appropriate article: The council debated at length over whether ______ rise in tuition charges was defensible in view of the prevailing economic conditions.`, o: [`a`, `an`, `the`, `no article`], e: `The correct option is (C). Explanation (Articles): We use the (definite article) when we refer to something specific or already understood from the context. Here, "whether the rise in tuition charges was defensible" refers to a particular rise being discussed by the council (a known, definite issue). Therefore, the correct sentence is: "...over whether the rise in tuition charges was defensible..." Why other options are incorrect: (A) a: "a rise" would suggest a non-specific, indefinite rise, which does not fit because the council is debating a particular rise. (B) an: "an" is used before vowel sounds, but "rise" starts with the consonant sound /r/, so "an rise" is incorrect. (D) no article: Without an article ("whether rise..."), the noun becomes grammatically unnatural in this context. S` },
  { s: `English Language`, q: `What does the idiom "to keep the wolf away from the door" mean?`, o: [`To avoid financial distress`, `To escape immediate physical danger`, `To guard against enemies`, `To avoid taking risks`], e: `The correct option is (A). Idiom Meaning: to keep the wolf away from the door means to manage somehow so that one does not suffer from hunger, poverty, or financial hardship. (Hindi meaning: ) Step-by-step reasoning: In idioms, "wolf" symbolically represents hunger and poverty. "Away from the door" suggests preventing hardship from entering one's life. Hence, the idiom refers to earning just enough to meet basic needs and avoid financial trouble. Example: He took a second job to keep the wolf away from the door. Other related idioms and meanings: make ends meet ­ to manage with the money one has ( ) live from hand to mouth ­ to live with barely enough money for basic needs ( ) tighten one's belt ­ to spend less due to financial difficulty ( ) So the correct answer is (a)` },
  { s: `English Language`, q: `Change the following from active to passive: The director was expected to have completed the script revisions before filming began.`, o: [`The script revisions were expected to have completed by the director before filming began.`, `The script revisions were expected to have been completed by the director before filming began.`, `The script revisions were being expected to have been completed by the director before filming began.`, `The script revisions were expected to being completed by the director before filming began.`], e: `The correct option is (B). Explanation (Active to Passive with perfect infinitive): Given sentence: "The director was expected to have completed the script revisions..." Here, the main verb phrase is was expected (past passive form of "expect"), and after it we have a perfect infinitive: to have completed. Rule: When a perfect infinitive (to have + V3) is made passive, it becomes to have been + V3. Object in active sense: the script revisions. This becomes the subject in passive construction. Therefore, correct passive form: The script revisions were expected to have been completed by the director before filming began. Why other options are incorrect: (A) "to have completed" is not converted to passive; it should be "to have been completed." (C) introduces "were being expected," which chan` },
  { s: `English Language`, q: `Choose the option that best expresses the same sentence in indirect speech: I said to her, "Do your parents live in Mumbai?"`, o: [`I asked her whether her parents live in Mumbai.`, `I asked her whether her parents lived in Mumbai.`, `I told her whether her parents lived in Mumbai.`, `I said to her whether her parents live in Mumbai.`], e: `The correct option is (B). Explanation (Direct to Indirect Speech: Yes/No question): The given sentence is an interrogative (question): "Do your parents live in Mumbai?" Rule 1: For yes/no questions, we use if or whether in indirect speech. Rule 2: Reporting verb "said to" changes to asked wChoepnyrriegphot r©tin2g0a26quAedsdtiao2n4.7 Rule 3 (Backshifting): When the reporting verb is in the past ("said"), present simple in the reported speech generally changes to past simple. So, "live" becomes lived. Correct conversion: I asked her whether her parents lived in Mumbai. Why other options are incorrect: (A) does not backshift "live" to "lived" even though the reporting verb is past. (C) uses "told," which is not used for questions; "told" is used for statements/commands. (D) keeps "said to" ` },
  { s: `English Language`, q: `Why other options are incorrect: (A) does not backshift “live” to “lived” even though the reporting verb is past. (C) uses “told,” which is not used for questions; “told” is used for statements/commands. (D) keeps “said to” and also keeps present tense; it is not a proper indirect speech structure. So the correct answer is (b)`, o: [`Unyielding`, `Neutral`, `Agreeable`, `Adaptable`], e: `The correct option is (A). INTRANSIGENT: Someone who is intransigent is unwilling to change their views, refuse compromise, and remain stubborn even when persuasion is given. (Hindi meaning: ) Example: The manager was intransigent about the deadline and refused any extension. Why (A) Unyielding is correct: Unyielding means not giving way, not softening, and not ready to compromise. (Hindi meaning: ) This meaning matches "intransigent" because both indicate firmness and refusal to change. Example: She remained unyielding in her decision despite criticism. Synonyms (for INTRANSIGENT): stubborn, inflexible, uncompromising, obstinate. Antonyms (for INTRANSIGENT): flexible, compliant, agreeable, accommodating. Meanings of all other options: (B) Neutral: not taking sides; impartial (Hindi meanin` },
  { s: `English Language`, q: `Which of the following best describes the grammatical structure of the sentence: "This entails that simultaneity is observer-dependent: what appears simultaneous to one observer may not be so to another..." Read the passage and answer the question: "Minkowski proposed that space and time are not separate arenas but fused into a single four-dimensional continuum, an idea that naturally follows from Einstein's Special Relativity. Within this model, time ceases to be an absolute Newtonian backdrop and instead becomes interlaced with the three spatial dimensions to form space-time. Events are located as points in this space-time, and their separation is measured not by ordinary Euclidean distance but by the relativistic interval, which remains invariant across reference frames. This entails that simultaneity is observer-dependent: what appears simultaneous to one observer may not be so to another moving relative to the first. When gravity is introduced through Einstein's General Relativity, the picture deepens further. Gravity is reconceived not as a Newtonian force but as the curvature of space-time produced by mass-energy. Objects travel along geodesics--paths determined by the geometry of curved space- time. A striking consequence is gravitational time dilation: clocks nearer a massive body tick more slowly than clocks farther away. This has been empirically verified, including observations that satellite clocks run slightly faster than clocks on Earth due to weaker gravitational influence."`, o: [`Simple sentence`, `Complex sentence`, `Compound sentence`, `Compound-complex sentence`], e: `The correct option is (B). Explanation (Context + Grammar): The sentence is: "This entails that simultaneity is observer-dependent: what appears simultaneous to one observer may not be so to another..." It has one main clause: This entails. It is followed by a subordinate clause introduced by that: that simultaneity is observer-dependent. Further, it contains an additional dependent idea after the colon: what appears simultaneous to one observer may not be so to another. The "what" clause functions as a dependent clause explaining the statement. A complex sentence contains one independent clause and one or more dependent (subordinate) clauses. Therefore, the best description is Complex sentence. Why other options are incorrect: (A) Simple sentence: A simple sentence has only one independen` },
  { s: `English Language`, q: `What is the closest meaning of "geodesics" in the context of the passage? Read the passage and answer the question: "Minkowski proposed that space and time are not separate arenas but fused into a single four-dimensional continuum, an idea that naturally follows from Einstein's Special Relativity. Within this model, time ceases to be an absolute Newtonian backdrop and instead becomes interlaced with the three spatial dimensions to form space-time. Events are located as points in this space-time, and their separation is measured not by ordinary Euclidean distance but by the relativistic interval, which remains invariant across reference frames. This entails that simultaneity is observer-dependent: what appears simultaneous to one observer may not be so to another moving relative to the first. When gravity is introduced through Einstein's General Relativity, the picture deepens further. Gravity is reconceived not as a Newtonian force but as the curvature of space-time produced by mass-energy. Objects travel along geodesics--paths determined by the geometry of curved space- time. A striking consequence is gravitational time dilation: clocks nearer a massive body tick more slowly than clocks farther away. This has been empirically verified, including observations that satellite clocks run slightly faster than clocks on Earth due to weaker gravitational influence."`, o: [`The most natural straight-like paths in curved space-time`, `Vibrations travelling through space as waves`, `Circular tracks created only by orbital pull`, `Fixed reference points used for measurement`], e: `The correct option is (A). Explanation (Meaning from the passage): The passage states: "Objects travel along geodesics--paths determined by the geometry of curved space-time." So, geodesics are the natural paths followed by objects when space-time is curved. They are the closest equivalent of a "straight line" in a curved geometry. Thus, the closest meaning is: The most natural straight-like paths in curved space-time. Why other options are incorrect: (B) refers to waves/vibrations, which relates to phenomena like electromagnetic waves or gravitational waves, not geodesics. (C) limits the meaning to circular tracks due to orbit, but geodesics can be many forms depending on curvature and are not restricted to circular orbits. (D) describes fixed reference points, which is unrelated to the i` },
  { s: `English Language`, q: `. In the sentence "Gravity is reconceived not as a NewtonCiaonpyforirgchet b©ut2a0s26thAedcduar2v4a7ture of space-time produced by mass-energy," the word "curvature" most nearly refers to: Read the passage and answer the question: "Minkowski proposed that space and time are not separate arenas but fused into a single four-dimensional continuum, an idea that naturally follows from Einstein's Special Relativity. Within this model, time ceases to be an absolute Newtonian backdrop and instead becomes interlaced with the three spatial dimensions to form space-time. Events are located as points in this space-time, and their separation is measured not by ordinary Euclidean distance but by the relativistic interval, which remains invariant across reference frames. This entails that simultaneity is observer-dependent: what appears simultaneous to one observer may not be so to another moving relative to the first. When gravity is introduced through Einstein's General Relativity, the picture deepens further. Gravity is reconceived not as a Newtonian force but as the curvature of space-time produced by mass-energy. Objects travel along geodesics--paths determined by the geometry of curved space- time. A striking consequence is gravitational time dilation: clocks nearer a massive body tick more slowly than clocks farther away. This has been empirically verified, including observations that satellite clocks run slightly faster than clocks on Earth due to weaker gravitational influence."`, o: [`Folding of solid matter`, `Bending limited only to planetary orbits`, `Warping of the structure of space and time`, `Distortion of instruments by energy fields`], e: `The correct option is (C). Explanation (Vocabulary in context): The passage says: "Gravity is reconceived not as a Newtonian force but as the curvature of space-time produced by mass-energy." Here, curvature does not mean bending of a physical object; it refers to the way mass-energy changes the geometry of space and time. This "warping" affects how objects move (they follow geodesics), which is the main idea of General Relativity. Therefore, "curvature" most nearly refers to warping of the structure of space and time. Why other options are incorrect: (A) "Folding of solid matter" is unrelated; space-time is not solid matter. (B) is too narrow and incorrect; curvature is not limited to planetary orbits only. (D) refers to instruments being distorted, which is not what the passage explains.` },
  { s: `English Language`, q: `Why other options are incorrect: (A) “Folding of solid matter” is unrelated; space-time is not solid matter. (B) is too narrow and incorrect; curvature is not limited to planetary orbits only. (D) refers to instruments being distorted, which is not what the passage explains. So the correct answer is (c)`, o: [`Impregnable`, `Permeable`, `Unshakable`, `Detached`], e: `The correct option is (B). IMPERvious: Impervious means not allowing liquid, air, or any substance to pass through; it can also mean not affected by something. (Hindi meaning: / ) Example: The raincoat is impervious to water. Why (B) Permeable is correct: Permeable means allowing liquids or gases to pass through. (Hindi meaning: ) This is the direct opposite of "impervious," which means not allowing passage. Example: Sand is permeable, so water drains through it easily. Synonyms (for IMPERVIOUS): impermeable, impenetrable, resistant, unaffected. Antonyms (for IMPERVIOUS): permeable, penetrable, absorbent, vulnerable. Meanings of all other options: (A) Impregnable: unable to be captured or broken into; very strong (Hindi meaning: /) (C) Unshakable: firm; not likely to change (Hindi meaning:` },
  { s: `English Language`, q: `Which of the following is the correct indirect speech conversion of the given sentence? Neha said, "Hurrah! I have cleared the final interview."`, o: [`Neha happily said that she has cleared the final interview.`, `Neha joyfully exclaimed that she had cleared the final interview.`, `Neha expressed with excitement that she has cleared the final interview.`, `Neha said with joy that she clears the final interview.`], e: `The correct option is (B). Explanation (Direct to Indirect Speech: Exclamation): "Hurrah!" expresses joy; therefore, reporting verb should change from "said" to exclaimed with joy / joyfully exclaimed. Rule 1: Interjection "Hurrah!" is removed and its (emotion) is expressed through the reporting verb. Rule 2 (Pronoun change): "I" changes to "she" because Neha is speaking. Rule 3 (Tense backshift): Present perfect "have cleared" changes to past perfect "had cleared" when the reporting verb is in the past. Thus the correct indirect speech is: Neha joyfully exclaimed that she had cleared the final interview. Why other options are incorrect: (A) keeps "has cleared" (no backshift), which is incorrect with past reporting verb. (C) also keeps "has cleared" and is less standard in exam pattern com` },
  { s: `English Language`, q: `Identify the error in the sentence: Of the four contestants, he was the slower.`, o: [`slower`, `was`, `contestants`, `four`], e: `The correct option is (A). Explanation (Degrees of Comparison): In the sentence, comparison is among four contestants (more than two persons). Rule: When comparison is among more than two, we generally use the superlative degree (fastest/slowest), not the comparative (faster/slower). "slower" is a comparative form and is used when comparing two items only. Correct sentence should be: "Of the four contestants, he was the slowest." Grammatical rule used: Comparative degree is used for two; superlative degree is used for more than two. Example: Among the three players, Rahul is the best (not better). Information booster: The structure "of the + number/group" strongly indicates superlative usage (the tallest of the five, the smartest of the class). So the correct answer is (a)` },
  { s: `English Language`, q: `Choose the correct one-word substitution for the sentence below: "In his very old age, he often behaves foolishly, and people find it hard to tolerate him."`, o: [`Decrepitude`, `Dotage`, `Adolescence`, `Prudence`], e: `The correct option is (B). Explanation: The sentence describes a person in very old age who behaves foolishly or irrationally, often due to senility. The word that expresses this state is Dotage. (Hindi meaning: ) Dotage refers to a period of life when an elderly person becomes weak-minded or foolish, often because of old age. This exactly matches the idea of foolish behaviour in extreme old age. Example: In his dotage, he began repeating the same stories every day. Meanings of the other options: (A) Decrepitude: extreme old age with physical weakness and decline (Hindi meaning: ) (C) Adolescence: the stage between childhood and adulthood (Hindi meaning: ) (D) Prudence: wise and careful behaviour; good judgment (Hindi meaning: ) So the correct answer is (b)` },
  { s: `English Language`, q: `Which of the following is incorrectly spelled?`, o: [`Obsolescence`, `Scrapple`, `Vanquish`, `Capitutilation`], e: `The correct option is (D). Explanation (Spelling): Option (D) "Capitutilation" is incorrectly spelt. The correct spelling is Capitulation, meaning the act of surrendering or giving up resistance, usually on agreed terms. (Hindi meaning: ) Example: The enemy's capitulation ended the long conflict. Parts of speech: "Capitulation" is a noun (name of an act/state). Meanings of all the given options: (A) Obsolescence: the state of becoming outdated or no longer used (Hindi meaning: ) (B) Scrapple: a food item made from pork scraps mixed with cornmeal and spices (Hindi meaning: - ) (C) Vanquish: to defeat completely (Hindi meaning: ) (D) Capitutilation: incorrect spelling; correct is capitulation () So the correct answer is (d)` },
  { s: `English Language`, q: `Read the sentence below and choose the meaning of the idiom that best fits the context: "Ms. Rao: We still have a few minutes before the meeting begins. I'll just sit back and take forty winks." What does the idiom "take forty winks" mean in this context?`, o: [`Chat casually for a while`, `Take a brief nap`, `Prepare notes quickly`, `Watch something quietly`], e: `The correct option is (B). Idiom Meaning: take forty winks means to take a short sleep or a brief nap, usually for a few minutes. (Hindi meaning: ) Reasoning from context: Ms. Rao says there are a few minutes before the meeting. "sit back" suggests relaxing, and "take forty winks" refers to quickly resting. Therefore, it clearly indicates a brief nap. Example: I took forty winks after lunch and felt refreshed. Other related idioms and meanings: catch some Zs ­ to sleep for a short time ( ) nap ­ a short sleep ( ) sleep like a log ­ to sleep very deeply ( ) So the correct answer is (b)` },
  { s: `English Language`, q: `Rearrange the parts of the sentence in the correct order: Ancient mythologies P. preserving cultural memory through oral traditions Q. while adapting to modern themes and retellings R. influencing contemporary fiction, cinema, and thought S. have transcended eras and borders,`, o: [`PRSQ`, `RPQS`, `PRQS`, `SQRP`], e: `The correct option is (D). Sentence Breakdown: 1. Fixed Start: "Ancient mythologies" (Subject) 2. S: "have transcended eras and borders," (Main Verb/Action) - This is the only part that provides a predicate for the subject. 3. Q: "while adapting to modern themes and retellings" (Subordinate Clause) - This explains how they transcended time. 4. R: "influencing contemporary fiction, cinema, and thought" (Result/Effect) - This explains the impact of that adaptation. 5. P: "preserving cultural memory through oral traditions" (Additional Detail/Function) - This fits as a concluding thought or a parallel action. Logical Order: The most coherent structure follows the subject with its primary action, then explores the evolution of that action. Subject: Ancient mythologies Verb: S (have transcended` },
  { s: `English Language`, q: `Choose the correct active voice form from the given options: The application may not be approved by him.`, o: [`He may not approve the application.`, `He might not approve the application.`, `He should not have approved the application.`, `He may not have approved the application.`], e: `The correct option is (A). Explanation (Passive to Active with modal): Passive sentence: "The application may not be approved by him." Here, modal verb is may and passive structure is: may + be + V3. Rule: To convert to active voice, keep the modal the same and change the verb to base form: may + V1. Agent "by him" becomes subject "He". Object "the application" remains object. Active structure: He may not approve the application. Why other options are incorrect: (B) uses "might," which changes the degree of possibility; the original uses "may." (C) changes modal meaning to obligation/regret ("should not have"), not present in the original sentence. (D) changes the structure to perfect ("may not have approved"), which indicates past possibility, not the simple modal passive given. So the co` },
  { s: `English Language`, q: `Choose the one that correctly represents the sentence in direct speech: Rohan admitted that he did not have enough time to revise his notes the previous day.`, o: [`Rohan said, "I don't have enough time to revise my notes the previous day."`, `Rohan said, "I didn't have enough time to revise my notes yesterday."`, `Rohan said, "I didn't have enough time to revise my notes the previous day."`, `Rohan said, "I hadn't had enough time to revise my notes yesterday."`], e: `The correct option is (B). Explanation (Indirect to Direct Speech): Indirect sentence: "Rohan admitted that he did not have enough time to revise his notes the previous day." We must convert it into direct speech by restoring the original speaker's words. Pronoun change: "he" becomes "I" because Rohan is speaking in direct speech. Time expression change: "the previous day" in indirect speech becomes yesterday in direct speech. Tense: "did not have" (past simple) remains appropriate as "didn't have" in direct speech. Thus: Rohan said, "I didn't have enough time to revise my notes yesterday." Why other options are incorrect: (A) uses present tense "don't have" and keeps "the previous day," which is incorrect for direct speech time reference. (C) keeps "the previous day" instead of converting` },
  { s: `English Language`, q: `Why other options are incorrect: (A) uses present tense “don’t have” and keeps “the previous day,” which is incorrect for direct speech time reference. (C) keeps “the previous day” instead of converting it to “yesterday,” which is less standard for direct speech conversion. (D) uses past perfect “hadn’t had,” which changes the tense unnecessarily and does not match the reported meaning here. So the correct answer is (b)`, o: [`Cursory`, `Thorough`, `Passionate`, `Elaborate`], e: `The correct option is (A). PREFUNCTORY: Prefunctory means done in a hurried, careless, and routine manner, without real interest or attention. (Hindi meaning: / ) Example: He gave a prefunctory apology and left immediately. Why (A) Cursory is correct: Cursory means quick and not detailed; superficial. (Hindi meaning: ) A prefunctory action is typically superficial and done without care, which matches "cursory." Example: She took a cursory glance at the report before signing it. Synonyms (for PREFUNCTORY): superficial, routine, mechanical, perfunctory. Antonyms (for PREFUNCTORY): thorough, careful, attentive, conscientious. Meanings of all the other given options: (B) Thorough: complete and detailed (Hindi meaning: /) (C) Passionate: showing strong feelings or enthusiasm (Hindi meaning: ) (` },
  { s: `English Language`, q: `Meanings of all the other given options: Thorough: complete and detailed (Hindi meaning: िव™ृत/पूण ) Passionate: showing strong feelings or enthusiasm (Hindi meaning: जोशीला) Elaborate: very detailed and complicated (Hindi meaning: िव™ृत/जिटल) So the correct answer is (a)`, o: [`Transparent`, `Confusing`, `Fluent`, `Bright`], e: `The correct option is (B). LUCID: Lucid means clear and easy to understand, especially in thought, expression, or writing. (Hindi meaning: ) Example: The teacher gave a lucid explanation of the topic. Why (B) Confusing is correct: Confusing means unclear, puzzling, and difficult to understand. (Hindi meaning: ) This is the opposite of lucid, which means clear. Example: The instructions were confusing and many students made mistakes. Synonyms (for LUCID): clear, intelligible, comprehensible, plain. Antonyms (for LUCID): confusing, unclear, obscure, ambiguous. Meanings of all the other given options: (A) Transparent: easy to see through; clear (Hindi meaning: ) (C) Fluent: able to speak/write smoothly (Hindi meaning: ) (D) Bright: giving much light; intelligent (Hindi meaning: /) So the corr` },
  { s: `English Language`, q: `Improve the sentence by selecting the correct form of tense from the options: She stated that she ______ the assignment before the deadline.`, o: [`will finish`, `has finished`, `had finished`, `finishes`], e: `The correct option is (C). Explanation (Sequence of Tenses): Reporting verb is in the past: stated. The finishing of the assignment happened before another past point ("before the deadline") and is reported from a past viewpoint. Rule: When an action is completed before another past action/time, we use Past Perfect: had + V3. So the correct sentence is: "She stated that she had finished the assignment before the deadline." Why other options are incorrect: (A) will finish: future tense does not fit because the statement is about completion before a deadline. (B) has finished: present perfect is not suitable with a past reporting verb in this pattern and does not clearly show completion before a past deadline. (D) finishes: simple present is incorrect in reported speech with past reporting v` },
  { s: `English Language`, q: `Fill in the blank with the appropriate adverb: The ordinance was enforced ________, without any public hearing.`, o: [`arbitrarily`, `instinctively`, `methodically`, `progressively`], e: `The correct option is (A). Explanation: The phrase "without any public hearing" shows that the ordinance was imposed without proper procedure and possibly in an unfair or random manner. Arbitrarily means in a random, capricious, or unfair way, based on personal decision rather than rules. (Hindi meaning: ) Therefore, "The ordinance was enforced arbitrarily..." is grammatically and contextually correct. Example: Rules cannot be applied arbitrarily; they must be consistent. Why other options are incorrect: (B) instinctively: means by instinct, automatically (Hindi: ); it does not match the idea of lacking public hearing. (C) methodically: means in a systematic way (Hindi: ); it contradicts the implied unfairness/procedural absence. (D) progressively: means gradually over time (Hindi: ); it d` },
  { s: `English Language`, q: `Improve the sentence by selecting the appropriate tense of the highlighted word: He played for an hour when I saw him asleep on the sofa.`, o: [`had played`, `has played`, `will have played`, `had been playing`], e: `The correct option is (D). Explanation (Past Continuous action before a past event): The sentence has two past references: (1) an activity continuing for a duration ("for an hour"), and (2) a past moment: "when I saw him asleep." It implies that the action (playing) was going on for some time before the moment I saw him asleep, and it provides duration. For an action that was continuing up to a past point and emphasizes duration, we use Past Perfect Continuous: had been + V1 + ing. Correct sentence: "He had been playing for an hour when I saw him asleep on the sofa." Grammatical rule used: Past Perfect Continuous is used for an action that started in the past and continued up to another past time, often with "for/since." Example: She had been studying for two hours when the lights went out` },
  { s: `English Language`, q: `Fill in the blank with the correctly spelt word: The ruler's ________ policies provoked widespread dissent.`, o: [`despotick`, `despotik`, `despotic`, `dispotic`], e: `The correct option is (C). Explanation (Correct spelling + contextual fit): The sentence needs an adjective describing harsh, tyrannical rule: "The ruler's ________ policies..." The correct spelling is despotic, meaning relating to a despot; tyrannical and oppressive. (Hindi meaning: ) Therefore, "despotic policies" correctly conveys policies made by a tyrant and fits the context of "widespread dissent." Example: The people protested against the despotic regime. Explain why other options are incorrect: (A) despotick: incorrect spelling; "-ick" ending is wrong here. (B) despotik: incorrect spelling; "k" ending is not used. (D) dispotic: incorrect spelling; "dis-" is wrong; correct root is "despot." Information booster: The noun is despot () and the adjective is despotic (). So the correct a` },
  { s: `English Language`, q: `Which of the following is the correct spelling of the word?`, o: [`Aesthatic`, `Aesthetic`, `Aesthetisc`, `Aesthestic`], e: `The correct option is (B). Explanation (Correct spelling): Option (B) "Aesthetic" is the correctly spelt word. Aesthetic means related to beauty, art, and the appreciation of pleasing appearance. (Hindi meaning: ) Example: The architect focused on the aesthetic appeal of the building. Parts of speech: "Aesthetic" is commonly used as an adjective (aesthetic design) and also as a noun in some contexts (modern aesthetics). Meanings of all the given options: (A) Aesthatic: incorrect spelling; intended meaning is "aesthetic" () (B) Aesthetic: related to beauty/art (Hindi: ) (C) Aesthetisc: incorrect spelling; extra "s" placement is wrong. (D) Aesthestic: incorrect spelling; letter order is incorrect. So the correct answer is (b)` }
];

if (RAW.length !== 100) { console.error(`Expected 100 questions, got ${RAW.length}`); process.exit(1); }

async function seed() {
  console.log('Connecting to MongoDB...');
  await mongoose.connect(MONGO_URI);
  console.log('Connected.');

  let category = await ExamCategory.findOne({ name: 'Central', type: 'Central' });
  if (!category) {
    category = await ExamCategory.create({ name: 'Central', type: 'Central', description: 'Central government competitive exams' });
  }

  let exam = await Exam.findOne({ code: 'SSC-SSP' });
  if (!exam) {
    exam = await Exam.create({
      category: category._id,
      name: 'SSC Selection Post (Graduate Level)',
      code: 'SSC-SSP',
      description: 'Staff Selection Commission - Selection Post (Graduate Level)',
      isActive: true
    });
  }

  const PATTERN_TITLE = 'SSC Selection Post (Graduate Level)';
  let pattern = await ExamPattern.findOne({ exam: exam._id, title: PATTERN_TITLE });
  if (!pattern) {
    pattern = await ExamPattern.create({
      exam: exam._id, title: PATTERN_TITLE, duration: 60, totalMarks: 200, negativeMarking: 0.5,
      sections: [
        { name: REA, totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 },
        { name: GA,  totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 },
        { name: QA,  totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 },
        { name: ENG, totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 }
      ]
    });
  }

  const TEST_TITLE = 'SSC Selection Post (Graduation) - 29 July 2025 Shift-1 [Similar Paper]';
  await PracticeTest.deleteMany({ examPattern: pattern._id, title: TEST_TITLE });

  const questions = RAW.map((r, i) => ({
    questionText: r.q,
    questionImage: '',
    options: r.o,
    optionImages: ['', '', '', ''],
    correctAnswerIndex: KEY[i] - 1,
    explanation: r.e || '',
    section: r.s,
    tags: ['SSC', 'Selection Post', 'Phase XIII', 'Graduate', 'PYQ', '2025', 'Similar Paper'],
    difficulty: 'medium'
  }));

  const test = await PracticeTest.create({
    examPattern: pattern._id, title: TEST_TITLE, totalMarks: 200, duration: 60,
    accessLevel: 'FREE', isPYQ: true, pyqYear: 2025, pyqShift: '1',
    pyqExamName: 'SSC Selection Post Phase XIII (Graduate) - Similar Paper', questions
  });
  console.log(`Created PYQ PracticeTest: ${test._id} (${test.questions.length} questions)`);

  await mongoose.disconnect();
  console.log('Done.');
}

seed().catch(err => { console.error('Seed failed:', err); process.exit(1); });
